if st.button("➕ Woche hinzufügen"):
    n = len(st.session_state.instances)
    st.session_state.instances.append(_empty_inst(f"Sonderwoche {n}"))
    st.rerun()

st.divider()

# ── Telefonliste + Samstags Fahrer (global) ──────────────────────────────────
tel_up = st.file_uploader("📞 Telefonliste (Excel, optional)", type=["xlsx"], key="tel_upload")
if tel_up:
    st.session_state.tel_json = parse_telefon_excel(tel_up)
    n = len(__import__("json").loads(st.session_state.tel_json))
    st.caption(f"✅ Telefonliste: {n} Gruppen")
elif st.session_state.get("tel_json"):
    st.caption("✅ Telefonliste bereits geladen")

sam_ups = st.file_uploader("🚗 Samstags-Dateien (mehrere Excel möglich)", type=["xlsx"],
                            accept_multiple_files=True, key="sam_upload")
if sam_ups:
    with st.spinner("Verarbeite Samstags-Dateien …"):
        st.session_state.sam_json = parse_samstag_excel(sam_ups)
    n = len(__import__("json").loads(st.session_state.sam_json))
    st.caption(f"✅ Samstags Fahrer: {n} Fahrer aus {len(sam_ups)} Dateien")
elif st.session_state.get("sam_json"):
    n = len(__import__("json").loads(st.session_state.sam_json))
    st.caption(f"✅ Samstags Fahrer bereits geladen: {n} Fahrer")

fa_ups = st.file_uploader("👤 Fahrerauswertung (mehrere Touren-Excel möglich)", type=["xlsx"],
                            accept_multiple_files=True, key="fa_upload")
if fa_ups:
    with st.spinner("Verarbeite Fahrerauswertung …"):
        st.session_state.fa_json = parse_fahrer_excel(fa_ups)
    n = len(__import__("json").loads(st.session_state.fa_json))
    st.caption(f"✅ Fahrerauswertung: {n} Fahrer aus {len(fa_ups)} Dateien")
elif st.session_state.get("fa_json"):
    n = len(__import__("json").loads(st.session_state.fa_json))
    st.caption(f"✅ Fahrerauswertung bereits geladen: {n} Fahrer")

kfz_up = st.file_uploader("🚛 Kennzahlen Fuhrpark (Excel, erstes Blatt wird gelesen)", type=["xlsx"], key="kfz_upload")
if kfz_up:
    with st.spinner("Lese Fuhrpark-Kennzahlen …"):
        st.session_state.kfz_json = parse_fuhrpark_excel(kfz_up)
    n = len(__import__("json").loads(st.session_state.kfz_json))
    st.caption(f"✅ Fuhrpark-Kennzahlen: {n} Kalenderwochen geladen")
elif st.session_state.get("kfz_json"):
    n = len(__import__("json").loads(st.session_state.kfz_json))
    st.caption(f"✅ Fuhrpark-Kennzahlen bereits geladen: {n} KW")

# ── Download ──────────────────────────────────────────────────────────────────
st.divider()
ready = [inst for inst in st.session_state.instances if inst["suche_html"] and inst["druck_html"]]
if ready:
    with st.spinner("Kombiniere …"):
        app_html = combine_html(
            instances=ready,
            tel_json=st.session_state.get("tel_json", "[]"),
            sam_json=st.session_state.get("sam_json", "[]"),
            kfz_json=st.session_state.get("kfz_json", "[]"),
            fa_json=st.session_state.get("fa_json", "[]"),
            last_updated=datetime.datetime.now().strftime("Stand: %d.%m.%Y %H:%M"),
        )
    st.download_button(
        label=f"⬇️  suche.html herunterladen ({len(ready)} Woche{'n' if len(ready) > 1 else ''})",
        data=app_html.encode("utf-8"),
        file_name="suche.html",
        mime="text/html",
        type="primary",
    )
    st.caption(f"Gesamtgröße: ca. {len(app_html)//1024} KB | Wochen: {', '.join(i['name'] for i in ready)}")
else:
    st.warning("Bitte mindestens eine Woche mit Wochen-Excel befüllen (globale Dateien nicht vergessen).")
